      if (settled) {
        return;
      }

      settled = true;
      clearTimeout(timeout);
      rejectOrigins(error);
    };

    const maybeResolve = () => {
      if (settled || !backendOrigin || !webOrigin) {
        return;
      }

      settled = true;
      clearTimeout(timeout);
      resolveOrigins({ backendOrigin, webOrigin });
    };

    const capture = (chunk, stream) => {
      const text = chunk.toString();
      output += text;
      stream.write(text);

      const backendMatch = text.match(/better-ao backend:\s*(\S+)/);
      if (backendMatch) {
        backendOrigin = backendMatch[1];
      }

      const webMatch = text.match(/better-ao web:\s*(\S+)/);
      if (webMatch) {
        webOrigin = webMatch[1];
      }

      maybeResolve();
    };

    child.stdout.on('data', (chunk) => capture(chunk, process.stdout));
    child.stderr.on('data', (chunk) => capture(chunk, process.stderr));
    child.on('error', fail);
    child.on('exit', (code, signal) => {
      if (settled) {
        return;
      }

      fail(
        new Error(
          `better-ao stack exited before it was ready: code=${code} signal=${signal}\n\n${output.trim()}`
        )
      );
    });
  });
}

async function waitForHealthyEndpoint(url) {
  const deadline = Date.now() + stackTimeoutMs;
  let lastError;

  while (Date.now() < deadline) {
    try {
      const response = await fetch(url, {
        signal: AbortSignal.timeout(1_000),
      });
      if (response.ok) {
        return;
      }
      lastError = new Error(`${url} returned ${response.status}`);
    } catch (error) {
      lastError = error;
    }

    await sleep(250);
  }

  throw new Error(`Timed out waiting for ${url}: ${lastError}`);
}

